 19→
 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→#include "riscv_nn_support.h"
 24→
 25→//// Convolution Functions
 26→int32_t riscv_nn_conv_HWC_u8_u8_s8_sym_bias_fast(const u8_t * in_tensor,
 27→        const uint16_t in_tensor_dim,
 28→        const uint16_t in_tensor_ch,
 29→        const q7_t * ker_weight,
 30→        const uint16_t out_tensor_ch,
 31→        const uint16_t ker_dim,
 32→        const uint16_t pad,
 33→        const uint16_t stride,
 34→        const q31_t * bias,
 35→        const uint16_t pre_rshift,
 36→        const uint16_t out_scale,
 37→        const uint16_t post_rshift,
 38→        u8_t * out_tensor,
 39→        const uint16_t out_tensor_dim,
 40→        q15_t * in_tmp_buf)
 41→{
 42→#ifdef ENA_EMPTY_FUN
 43→    //empty body
 44→#else
 45→    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0)
 46→    {
 47→        /* check if the input dimension meets the constraints */
 48→        return -1;
 49→    }
 50→
 51→#if defined(ENA_VEC_ISA) && defined(ENA_TILING)
 52→    /* cache is 512KB, type is u8 */
 53→    uint32_t tiling_size = 256;
 54→    /* num of columnar */
 55→    int col_counter = 0;
 56→    int16_t    i_out_y, i_out_x, i_ker_y, i_ker_x;
 57→    unsigned long addr_in_tmp_buf;
 58→
 59→    /*
 60→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
 61→     *  im2col are done to output in q15_t format from u8_t input
 62→     */
 63→    const long align_byte = 64;
 64→    u8_t *pBuffer = (u8_t*)in_tmp_buf;
 65→    u8_t *pOut = out_tensor;
 66→    q31_t *dst_q31;
 67→
 68→    q7_t *src2 = (q7_t *)in_tmp_buf
 69→                         + sizeof(*in_tensor) * tiling_size * in_tensor_ch * ker_dim * ker_dim; //matrix_A's memory space
 70→    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
 71→    addr_in_tmp_buf = (unsigned long)src2;
 72→    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch * ker_dim * ker_dim;
 73→    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
 74→    dst_q31 = (q31_t *)addr_in_tmp_buf;
 75→
 76→    /* transpose the kernel_weight for matrix multiplication */
 77→    const long row = out_tensor_ch;
 78→    const long col = ker_dim * ker_dim * in_tensor_ch;
 79→    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);
 80→
 81→    /* This part implements the im256col function */
 82→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
 83→    {
 84→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
 85→        {
 86→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
 87→            {
 88→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
 89→                {
 90→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
 91→                    {
 92→                        /* Filling 0 for out-of-bound paddings */
 93→                        nn_set_zero_u8(pBuffer, sizeof(u8_t) * in_tensor_ch);
 94→                    }
 95→                    else
 96→                    {
 97→                        /* Copying the pixel data to column */
 98→                        nn_dup_u8(in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
 99→                    }
100→                    pBuffer += in_tensor_ch;
101→                }
102→            }
103→            col_counter++;
104→
105→            /* Computation is filed for [tiling_size] columns */
106→            if (col_counter == tiling_size)
107→            {
108→                pOut = nn_mat_mul_kernel_tiling_bias_u8_u8_s8((u8_t *)in_tmp_buf,
109→                                                              src2,
110→                                                              dst_q31,
111→                                                              pOut,
112→                                                              col_counter,
113→                                                              in_tensor_ch * ker_dim * ker_dim,
114→                                                              out_tensor_ch,
115→                                                              pre_rshift,
116→                                                              out_scale,
117→                                                              post_rshift,
118→                                                              bias,
119→                                                              tiling_size);
120→                /* reset */
121→                col_counter = 0;
122→                pBuffer = (u8_t *)in_tmp_buf;
123→            }
124→        }
125→    }
126→
127→    /* check if there is left-over for compute */
128→    pOut = nn_mat_mul_kernel_tiling_bias_u8_u8_s8((u8_t *)in_tmp_buf,
129→                                                  src2,
130→                                                  dst_q31,
131→                                                  pOut,
132→                                                  col_counter,
133→                                                  in_tensor_ch * ker_dim * ker_dim,
134→                                                  out_tensor_ch,
135→                                                  pre_rshift,
136→                                                  out_scale,
137→                                                  post_rshift,
138→                                                  bias,
139→                                                  tiling_size);
140→#elif defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA_V5)
141→    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
142→
143→    /*
144→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
145→     *  im2col are done to output in q15_t format from q7_t input
146→     */
147→
148→    u8_t     *pBuffer = (u8_t*)in_tmp_buf;
149→    u8_t     *pOut = out_tensor;
150→    int bound_begin = (pad + stride - 1) / stride;
151→    int bound_end   = (in_tensor_dim + pad - ker_dim + stride) / stride;
152→
153→    /*
154→     *  Here we split the entire matrix into three regions depending on the pad situation
155→     *    Top: i_out_y from 0 to pad - 1
156→     * Middle: i_out_y from pad to out_tensor_dim-pad-1
157→     * Bottom: i_out_y from out_tensor_dim-pad to out_tensor_dim-1
158→     */
159→
160→    /* top part */
161→    for (i_out_y = 0; i_out_y < bound_begin; i_out_y++)
162→    {
163→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
164→        {
165→            /* This part implements the im2col function */
166→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
167→            {
168→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
169→                {
170→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
171→                    {
172→                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
173→                    }
174→                    else
175→                    {
176→                        nn_dup_u8
177→                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
178→                    }
179→                    pBuffer += in_tensor_ch;
180→                }
181→            }
182→
183→            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
184→            {
185→                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
186→                        (u8_t*)in_tmp_buf,
187→                        out_tensor_ch,
188→                        in_tensor_ch * ker_dim * ker_dim,
189→                        pre_rshift,
190→                        out_scale,
191→                        post_rshift,
192→                        bias,
193→                        pOut);
194→                /* counter reset */
195→                pBuffer = (u8_t *)in_tmp_buf;
196→            }
197→        }
198→    }
199→
200→    /* middle part, here we also divide the x into left, mid and right */
201→    for (; i_out_y < bound_end; i_out_y++)
202→    {
203→        /* left part */
204→        for (i_out_x = 0; i_out_x < bound_begin; i_out_x++)
205→        {
206→            /* This part implements the im2col function */
207→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
208→            {
209→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
210→                {
211→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
212→                    {
213→                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
214→                    }
215→                    else
216→                    {
217→                        nn_dup_u8
218→                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
219→                    }
220→                    pBuffer += in_tensor_ch;
221→                }
222→            }
223→
224→            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
225→            {
226→                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
227→                        (u8_t*)in_tmp_buf,
228→                        out_tensor_ch,
229→                        in_tensor_ch * ker_dim * ker_dim,
230→                        pre_rshift,
231→                        out_scale,
232→                        post_rshift,
233→                        bias,
234→                        pOut);
235→                /* counter reset */
236→                pBuffer = (u8_t *)in_tmp_buf;
237→            }
238→        }
239→
240→        /* mid part */
241→        for (; i_out_x < bound_end; i_out_x++)
242→        {
243→            /* This part implements the im2col function */
244→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
245→            {
246→                nn_dup_u8
247→                ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_out_x * stride - pad) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim);
248→                pBuffer += in_tensor_ch * ker_dim;
249→            }
250→
251→            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
252→            {
253→                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
254→                        (u8_t*)in_tmp_buf,
255→                        out_tensor_ch,
256→                        in_tensor_ch * ker_dim * ker_dim,
257→                        pre_rshift,
258→                        out_scale,
259→                        post_rshift,
260→                        bias,
261→                        pOut);
262→                /* counter reset */
263→                pBuffer = (u8_t *)in_tmp_buf;
264→            }
265→        }
266→
267→        /* right part */
268→        for (; i_out_x < out_tensor_dim; i_out_x++)
269→        {
270→            /* This part implements the im2col function */
271→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
272→            {
273→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
274→                {
275→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
276→                    {
277→                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
278→                    }
279→                    else
280→                    {
281→                        nn_dup_u8
282→                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
283→                    }
284→                    pBuffer += in_tensor_ch;
285→                }
286→            }
287→
288→            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
289→            {
290→                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
291→                        (u8_t*)in_tmp_buf,
292→                        out_tensor_ch,
293→                        in_tensor_ch * ker_dim * ker_dim,
294→                        pre_rshift,
295→                        out_scale,
296→                        post_rshift,
297→                        bias,
298→                        pOut);
299→                /* counter reset */
300→                pBuffer = (u8_t *)in_tmp_buf;
301→            }
302→        }
303→    }
304→
305→    for (; i_out_y < out_tensor_dim; i_out_y++)
306→    {
307→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
308→        {
309→            /* This part implements the im2col function */
310→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
311→            {
312→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
313→                {
314→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
315→                    {
316→                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
317→                    }
318→                    else
319→                    {
320→                        nn_dup_u8
321→                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
322→                    }
323→                    pBuffer += in_tensor_ch;
324→                }
325→            }
326→
327→            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
328→            {
329→                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
330→                        (u8_t*)in_tmp_buf,
331→                        out_tensor_ch,
332→                        in_tensor_ch * ker_dim * ker_dim,
333→                        pre_rshift,
334→                        out_scale,
335→                        post_rshift,
336→                        bias,
337→                        pOut);
338→                /* counter reset */
339→                pBuffer = (u8_t *)in_tmp_buf;
340→            }
341→        }
342→    }
343→
344→    /* check if there is left-over for compute */
345→#ifdef ENA_VEC_ISA
346→#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
347→    if (pBuffer != (u8_t *)in_tmp_buf)
348→    {
349→        unsigned vl;
350→        const q7_t *p_wt = ker_weight;
351→        int       i;
352→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
353→
354→        // NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
355→        vl = __riscv_vsetvl_e32m1(1);
356→        // NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum
357→        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum
358→
359→        for (i = 0; i < out_tensor_ch; i++)
360→        {
361→            u8_t      *p_in = (u8_t*)in_tmp_buf;
362→            uint16_t colCnt2 = colCnt;
363→
364→            //clear v0~v7
365→            vl = __riscv_vsetvl_e32m8(colCnt);
366→            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
367→
368→            while (colCnt2 > 0)
369→            {
370→                vl = __riscv_vsetvl_e8m8(colCnt2);
371→                //load src1
372→                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
373→                //load src2
374→                vuint8m8_t vP_in_u8m8 = __riscv_vle8_v_u8m8(p_in, vl);
375→                //bump pointers and update loop counter
376→                colCnt2 -= vl;
377→                p_wt += vl;
378→                p_in += vl;
379→                //set the proper avl/SEW/LMUL values for vd4dot
380→                vl >>= 2;
381→                vl = __riscv_vsetvl_e32m8(vl);
382→                //acc += src1 * src2
383→                vAccumulator = __riscv_vd4dotsu_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_u8m8, vl);
384→            }
385→
386→            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
387→            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
388→
389→            //add bias back
390→            vl = __riscv_vsetvl_e32m1(1);
391→            vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
392→            vSum = __riscv_vadd(vSum, vBias, vl);
393→
394→            //2-stage shift
395→            vSum = __riscv_vsra(vSum, pre_rshift, vl);
396→            vSum = __riscv_vmul(vSum, out_scale, vl);
397→            vSum = __riscv_vadd(vSum, NN_ROUND(post_rshift), vl);
398→
399→            //scale down, clip and store the results
400→            vSum = __riscv_vmax(vSum, 0, vl);
401→            vl = __riscv_vsetvl_e16mf2(1);
402→            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, post_rshift, vl);
403→            vl = __riscv_vsetvl_e8mf4(1);
404→            vuint16mf2_t vSum_u16mf2 = __riscv_vreinterpret_u16mf2(vSum_i16mf2);
405→            vuint8mf4_t vpOut = __riscv_vnclipu(vSum_u16mf2, 0, __RISCV_VXRM_RNU, vl);
406→            __riscv_vse8(pOut, vpOut, vl);
407→            bias += vl;
408→            pOut += vl;
409→        }
410→    }
411→#elif (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
412→    if (pBuffer != (u8_t *)in_tmp_buf)
413→    {
414→        unsigned vl;
415→        const q7_t *p_wt = ker_weight;
416→        int       i;
417→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
418→
419→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
420→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum
421→
422→        for (i = 0; i < out_tensor_ch; i++)
423→        {
424→            u8_t      *p_in = (u8_t*)in_tmp_buf;
425→            uint16_t colCnt2 = colCnt;
426→
427→            //clear v0~v7
428→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
429→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
430→
431→            while (colCnt2 > 0)
432→            {
433→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
434→                //load src1
435→                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
436→                //load src2
437→                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
438→                //bump pointers and update loop counter
439→                colCnt2 -= vl;
440→                p_wt += vl;
441→                p_in += vl;
442→                //set the proper avl/SEW/LMUL values for vd4dot
443→                vl >>= 2;
444→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
445→                //acc += src1 * src2
446→                NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
447→            }
448→
449→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
450→            NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V31);
451→
452→            //add bias back
453→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
454→            NDS_VEC_VLW_V(NDS_VEC_V9, bias);
455→            NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V9);
456→
457→            //2-stage shift
458→            NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
459→            NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V8, out_scale);
460→            NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, NN_ROUND(post_rshift));
461→
462→            //scale down, clip and store the results
463→            NDS_VEC_VMAX_VX(NDS_VEC_V8, NDS_VEC_V8, 0);
464→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
465→            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
466→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
467→            NDS_VEC_VNCLIPU_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
468→            NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
469→            bias += vl;
470→            pOut += vl;
471→        }
472→    }
